ValidationRule.errorConditionFormula:
AND(
            RecordType.DeveloperName = 'Customer_Survey_Index',
            ISCHANGED(Status),
            NOT(
                OR(
                    /* From New: can go to any later status */
                    AND(
                        TEXT(PRIORVALUE(Status)) = 'New',
                        OR(
                            ISPICKVAL(Status, 'In Progress'),
                            ISPICKVAL(Status, 'Overdue'),
                            ISPICKVAL(Status, 'Escalated'),
                            ISPICKVAL(Status, 'Closed')
                        )
                    ),
                    /* From In Progress: can go to Overdue, Escalated, Closed */
                    AND(
                        TEXT(PRIORVALUE(Status)) = 'In Progress',
                        OR(
                            ISPICKVAL(Status, 'Overdue'),
                            ISPICKVAL(Status, 'Escalated'),
                            ISPICKVAL(Status, 'Closed')
                        )
                    ),
                    /* From Overdue: can go to Escalated, Closed */
                    AND(
                        TEXT(PRIORVALUE(Status)) = 'Overdue',
                        OR(
                            ISPICKVAL(Status, 'Escalated'),
                            ISPICKVAL(Status, 'Closed')
                        )
                    ),
                    /* From Escalated: can go only to Closed */
                    AND(
                        TEXT(PRIORVALUE(Status)) = 'Escalated',
                        ISPICKVAL(Status, 'Closed')
                    )
                    /* From Closed: no change allowed — any change will fail the allowed list above */
                )
            )
        )
